const DUFS_URL = 'https://drop.ewutelo.cloud';
const FILENAME = 'incidents-otn-oob-v2.xlsx';
const resp = await this.helpers.httpRequest({ method: 'GET', url: `${DUFS_URL}/${encodeURIComponent(FILENAME)}`, encoding: 'arraybuffer', returnFullResponse: true });
if (resp.statusCode !== 200) throw new Error(`DUFS download failed: HTTP ${resp.statusCode}`);
const buf = Buffer.from(resp.body);
return [{ json: { status: 'downloaded', size: buf.length, filename: FILENAME }, binary: { 'incidents.xlsx': { data: buf.toString('base64'), mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet', fileName: FILENAME } } }];

const LITELLM_URL = 'https://llm.ewutelo.cloud';
const LITELLM_KEY = 'sk-lm-08041985e12102015m';
const b64 = $input.first().binary['incidents.xlsx'].data;
const prompt = 'Extrais la feuille Incidents du fichier Excel. Retourne un JSON array. Chaque objet: {incident_id, categorie, sous_type, reseau, criticite, symptome, impact, cause_probable, alarme_lightsoft, alarme_vizee, sops, site, cas_reels}. UNIQUEMENT le JSON array.';
const result = await this.helpers.httpRequest({ method: 'POST', url: `${LITELLM_URL}/v1/chat/completions`, headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${LITELLM_KEY}` }, body: JSON.stringify({ model: 'mop-ingest', messages: [{ role: 'user', content: [{ type: 'text', text: prompt }, { type: 'image_url', image_url: { url: `data:application/vnd.openxmlformats-officedocument.spreadsheetml.sheet;base64,${b64}` } }] }], max_tokens: 16000 }) });
const raw = result.choices[0].message.content;
const clean = raw.replace(/^```(?:json)?\s*/m, '').replace(/\s*```\s*$/m, '').trim();
const incidents = JSON.parse(clean);
const body = ($input.first().json.body || {});
const filterIds = body.incident_ids;
const filtered = filterIds ? incidents.filter(i => filterIds.includes(i.incident_id)) : incidents;
return filtered.map(i => ({ json: i }));

const LLM = 'https://llm.ewutelo.cloud';
const LLM_KEY = 'sk-lm-08041985e12102015m';
const QD = 'https://qd.ewutelo.cloud';
const QD_KEY = 'sk-qd-08041985e12102015m';
const i = $input.item.json;
const query = [i.sous_type, i.alarme_lightsoft, i.symptome, i.categorie].filter(Boolean).join(' — ');
const embedResp = await this.helpers.httpRequest({ method: 'POST', url: `${LLM}/v1/embeddings`, headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${LLM_KEY}` }, body: JSON.stringify({ model: 'mop-embed', input: [query] }) });
const searchResp = await this.helpers.httpRequest({ method: 'POST', url: `${QD}/collections/mop_kb/points/search`, headers: { 'Content-Type': 'application/json', 'api-key': QD_KEY }, body: JSON.stringify({ vector: embedResp.data[0].embedding, limit: 5, with_payload: true, score_threshold: 0.5 }) });
const chunks = (searchResp.result || []).map(r => ({ filename: r.payload.filename || '', score: Math.round(r.score * 1000) / 1000, text: (r.payload.text || '').slice(0, 400) }));
return [{ json: { ...i, contexte_kb: JSON.stringify(chunks) } }];

const items = $input.all();
const generated = [], errors = [];
for (const item of items) {
  const r = item.json;
  if (r.pdf_url) generated.push({ incident_id: r.incident_id, pdf_url: r.pdf_url, docx_url: r.docx_url });
  else errors.push({ incident_id: r.incident_id, error: r.message || 'unknown' });
}
return [{ json: { total: items.length, generated: generated.length, errors: errors.length, results: generated, failures: errors, generated_at: new Date().toISOString() } }];
